    /// <summary>
    /// 获取菜单，平铺数据
    /// </summary>
    /// <param name="menuSearch"></param>
    /// <param name="AuthBusiness"></param>
    /// <param name="assetExecuter"></param>
    /// <returns></returns>
    [HttpPost]
    [TPOK]
    public TPResponse<List<Menu_Class>> GetMenus(
        [FromBody] Menu_Search menuSearch,
        [FromServices] IAuthBusiness AuthBusiness,
        [FromServices] IAssetExecuter assetExecuter)
    {
        var (test, msg, keys) = GetMenuKeys(AuthBusiness, assetExecuter);

        if (test)
        {
            var res = new List<Menu_Class>();
            if (msg == "OK")
            {
                res = MenuBusiness.SearchBy_Codes(keys);
            }
            else if (msg == "All")
            {
                res = MenuBusiness.GetAll();
            }

            if (!string.IsNullOrEmpty(menuSearch.Code))
            {
                res = res.FindAll(x => x.Code == menuSearch.Code);
            }
            if (!string.IsNullOrEmpty(menuSearch.Label))
            {
                res = res.FindAll(x => x.Label.Contains(menuSearch.Label));
            }

            res = res.OrderBy(x => x.Sort).ThenBy(x => x.Parent_id).ToList();

            return TPResponse.New(res);
        }
        else
        {
            return TPResponse.Bad<List<Menu_Class>>(msg, null);
        }

    }

    /// <summary>
    /// 获取有权限的菜单Key
    /// </summary>
    /// <param name="AuthBusiness"></param>
    /// <param name="assetExecuter"></param>
    /// <returns></returns>
    private static (bool Status, string Msg, List<string> MenuKeys) GetMenuKeys(
        IAuthBusiness AuthBusiness, IAssetExecuter assetExecuter)
    {
        if (!Config.BaseConfig.UsingAuth)
        {
            return (true, "All", null);
        }

        var (account, userName) = ScopeUser.GetUserAccountName();
        var groups = AuthBusiness.GetAssetsForUser(account);
        var assets = assetExecuter.GetAssetsResult(groups);
        if (assets == null)
        {
            return (false, "无权限", null);
        }
        else
        {
            var menuAssets = assets.FindAll(x => x.AssetName == "Menu");
            var keys = new List<string>();
            foreach (var item in menuAssets)
            {
                keys.AddRange(item.Patterns);
            }
            return (true, "OK", keys);
        }
    }


