    /// <summary>
    /// 创建菜单视图
    /// </summary>
    /// <returns></returns>
    [HttpPost]
    [Tags("创建菜单视图")]
    public TPResponse<string> MakeViewsByMenus()
    {
        var codeDir = Common.CurrentDllPath.Replace("\\Backend_cs\\bin\\Debug\\net8.0\\", "") +
                      "\\Frontend\\src\\views\\";
        Directory.CreateDirectory(codeDir);

        var menus = MenuBusiness.GetAll()
            .OrderBy(x => x.Sort).ToList();

        var list1 = new List<string>();
        var list2 = new List<string>();

        foreach (var menu in menus)
        {
            var menuPattern = "P" + menu.Sort.ToString() + "_" + menu.Code;

            var subPath = codeDir + menuPattern + "\\";
            Directory.CreateDirectory(subPath);

            if (!System.IO.File.Exists(subPath + menuPattern + "_req.js"))
            {
                var jsContent = "import request from '@utility/request';";
                System.IO.File.WriteAllText(subPath + menuPattern + "_req.js", jsContent);
            }

            if (!System.IO.File.Exists(subPath + menuPattern + ".vue"))
            {
                var vueContent = "<script setup></script>\r\n<template></template>\r\n<style scoped></style>";
                System.IO.File.WriteAllText(subPath + menuPattern + ".vue", vueContent);
            }

            list1.Add("import " + menuPattern + " from '../views/" + menuPattern + "/" + menuPattern + ".vue';");
            list2.Add("<" + menuPattern + " v-else-if=\"menuKey == '" + menu.Code + "'\"></" + menuPattern + ">");

        }

        list1.Add("");
        list1.AddRange(list2);
        System.IO.File.WriteAllLines(codeDir + "GenCode.txt", list1);

        return TPResponse.New(codeDir);
    }

